      console.warn('PostFX disabled:', err);
      this.enabled = false;
    }
  }

  setSize(w, h) {
    if (this.composer) this.composer.setSize(w, h);
  }

  render() {
    if (this.enabled && this.composer) this.composer.render();
    else this.renderer.render(this.scene, this.camera);
  }
}
