        <div class="row"><span class="key">◀ ▶ ▲ ▼</span> / <span class="key">W</span><span class="key">A</span><span class="key">S</span><span class="key">D</span> <b>move</b></div>
        <div class="row" style="margin-top:8px"><span class="key">Space</span><span class="key">J</span><span class="key">Z</span> <b>fire</b> &nbsp;·&nbsp; <span class="key">Shift</span><span class="key">C</span><span class="key">K</span> <b>spend power</b></div>
        <div class="row" style="margin-top:8px"><span class="key">P</span><span class="key">Esc</span> <b>pause</b> &nbsp;·&nbsp; on touch: <b>drag to fly, hold to fire</b></div>
        <div style="margin-top:14px; color:#7f8bb5">Grab capsules → the meter advances → spend it on<br><b>Speed · Missile · Double · Laser · Option · Force&nbsp;Field</b></div>
      </div>
    </div>

    <!-- Game over -->
    <div class="screen" id="screen-gameover">
      <div class="go-title">GAME OVER</div>
      <div class="final">Score <b id="final-score">0000000</b><br>Best <b id="final-hi">0000000</b></div>
      <div class="prompt">▶ PRESS ENTER / TAP TO CONTINUE</div>
    </div>

    <!-- Pause -->
    <div class="screen" id="screen-pause">
      <div class="go-title" style="color:var(--cyan);text-shadow:var(--glow-cyan)">PAUSED</div>
      <div class="prompt">▶ PRESS P / ESC TO RESUME</div>
    </div>
  </div>

  <script type="importmap">
  {
    "imports": {
      "three": "./vendor/three/three.module.js",
      "three/addons/": "./vendor/three/addons/"
    }
  }
  </script>
  <script type="module" src="./src/main.js"></script>
</body>
</html>
